    private function formatBookingDate(string $rawDate): string
    {
        $rawDate = trim($rawDate);
        if ($rawDate === '') {
            return '';
        }

        $parsedDate = \DateTime::createFromFormat('Y-m-d', $rawDate)
            ?: \DateTime::createFromFormat('d/m/Y', $rawDate)
            ?: date_create($rawDate);

        if ($parsedDate === false) {
            return $rawDate;
        }

        return $parsedDate->format('d/m/Y');
    }

    private function formatBookingDateTime(?string $rawDateTime): string
    {
        $rawDateTime = trim((string) $rawDateTime);
        if ($rawDateTime === '') {
            return '';
        }

        $parsedDateTime = \DateTime::createFromFormat('Y-m-d H:i:s', $rawDateTime)
            ?: date_create($rawDateTime);

        if ($parsedDateTime === false) {
            return $rawDateTime;
        }

        return $parsedDateTime->format('d/m/Y H:i');
    }

    private function createEmailService()
    {
        $email = Services::email();
        $email->SMTPTimeout = 8;

        return $email;
    }

    private function sendEmailWithFallback($to, string $subject, string $message, bool $isHtml = false): bool
    {
        $emailConfig = config('Email');
        $accounts = $emailConfig->accounts ?? [];

        if ($accounts === []) {
            $accounts = [[
                'fromEmail' => $emailConfig->fromEmail,
                'fromName' => $emailConfig->fromName,
                'SMTPUser' => $emailConfig->SMTPUser,
                'SMTPPass' => $emailConfig->SMTPPass,
            ]];
        }

        foreach ($accounts as $account) {
            try {
                $email = $this->createEmailService();
                $email->fromEmail = $account['fromEmail'] ?? $emailConfig->fromEmail;
                $email->fromName = $account['fromName'] ?? $emailConfig->fromName;
                $email->SMTPUser = $account['SMTPUser'] ?? $emailConfig->SMTPUser;
                $email->SMTPPass = $account['SMTPPass'] ?? $emailConfig->SMTPPass;
                $email->setFrom($email->fromEmail, $email->fromName);
                $email->setTo($to);
                $email->setSubject($subject);
                $email->setMailType($isHtml ? 'html' : 'text');
                $email->setMessage($message);

                if ($email->send()) {
                    return true;
                }

                log_message('error', 'Fallo envio SMTP con ' . ($email->fromEmail ?? 'sin cuenta') . ': ' . $email->printDebugger(['headers']));
            } catch (\Throwable $e) {
                log_message('error', 'Fallo envio SMTP con ' . (($account['fromEmail'] ?? '') ?: 'sin cuenta') . ': ' . $e->getMessage());
            }
        }

        return false;
    }

    private function resolveCustomerEmail(array $booking): string
    {
        $customersModel = new CustomersModel();

        if (!empty($booking['id_customer'])) {
            $customer = $customersModel->find($booking['id_customer']);
            $customerEmail = trim((string) ($customer['email'] ?? ''));
            if ($customerEmail !== '' && filter_var($customerEmail, FILTER_VALIDATE_EMAIL)) {
                return $customerEmail;
            }
        }

        $phone = trim((string) ($booking['phone'] ?? ''));
        if ($phone === '') {
            return '';
        }

        $customer = $customersModel->groupStart()
            ->where('phone', $phone)
            ->orWhere('complete_phone', $phone)
            ->groupEnd()
            ->first();

        $customerEmail = trim((string) ($customer['email'] ?? ''));
        if ($customerEmail !== '' && filter_var($customerEmail, FILTER_VALIDATE_EMAIL)) {
            return $customerEmail;
        }

        return '';
    }

    private function getSpecialBookingRequestStatusLabel(string $status): string
    {
        switch ($status) {
            case 'confirmed':
                return 'Confirmada';
            case 'cancelled':
                return 'Cancelada';
            case 'replied':
                return 'Respondida';
            case 'viewed':
                return 'Vista';
            default:
                return 'Nueva';
        }
    }

    private function getSpecialBookingRequestEffectiveStatus(array $request): string
    {
        $status = (string) ($request['status'] ?? 'new');
        if (in_array($status, ['cancelled', 'confirmed'], true)) {
            return $status;
        }

        $requestedDate = trim((string) ($request['requested_date'] ?? ''));
        $fieldId = !empty($request['field_id']) ? (int) $request['field_id'] : 0;
        $timeFrom = trim((string) ($request['time_from'] ?? ''));
        $timeUntil = trim((string) ($request['time_until'] ?? ''));

        if ($requestedDate === '' || $fieldId <= 0 || $timeFrom === '' || $timeUntil === '') {
            return $status;
        }

        $bookingsModel = new BookingsModel();
        $bookingQuery = $bookingsModel->where('date', $requestedDate)
            ->where('id_field', $fieldId)
            ->where('time_from', $timeFrom)
            ->where('time_until', $timeUntil)
            ->where('annulled', 0);

        $phone = trim((string) ($request['customer_phone'] ?? ''));
        if ($phone !== '') {
            $bookingQuery->where('phone', $phone);
        }

        return $bookingQuery->first() ? 'confirmed' : $status;
    }

    private function transformSpecialBookingRequest(array $request): array
    {
        $requestedDate = trim((string) ($request['requested_date'] ?? ''));
        $createdAt = trim((string) ($request['created_at'] ?? ''));
        $formattedCreatedAt = $createdAt !== '' ? date('d/m/Y H:i', strtotime($createdAt)) : '';
        $effectiveStatus = $this->getSpecialBookingRequestEffectiveStatus($request);

        return [
            'id' => (int) ($request['id'] ?? 0),
            'requested_date' => $requestedDate,
            'requested_date_display' => $requestedDate !== '' ? $this->formatBookingDate($requestedDate) : 'Fecha a confirmar',
            'customer_id' => !empty($request['customer_id']) ? (int) $request['customer_id'] : null,
            'field_id' => !empty($request['field_id']) ? (int) $request['field_id'] : null,
            'field_name' => (string) ($request['field_name'] ?? ''),
            'customer_name' => (string) ($request['customer_name'] ?? ''),
            'customer_last_name' => (string) ($request['customer_last_name'] ?? ''),
            'customer_phone' => (string) ($request['customer_phone'] ?? ''),
            'customer_email' => (string) ($request['customer_email'] ?? ''),
            'customer_dni' => (string) ($request['customer_dni'] ?? ''),
            'customer_city' => (string) ($request['customer_city'] ?? ''),
            'customer_type_institution' => (string) ($request['customer_type_institution'] ?? ''),
            'time_from' => (string) ($request['time_from'] ?? ''),
            'time_until' => (string) ($request['time_until'] ?? ''),
            'time_display' => trim(((string) ($request['time_from'] ?? '')) . ((((string) ($request['time_from'] ?? '')) !== '' || ((string) ($request['time_until'] ?? '')) !== '') ? ' a ' : '') . ((string) ($request['time_until'] ?? ''))),
            'visitors' => (int) ($request['visitors'] ?? 0),
            'minimum_visitors' => (int) ($request['minimum_visitors'] ?? 0),
            'total_amount' => $request['total_amount'] !== null ? (float) $request['total_amount'] : null,
            'status' => $effectiveStatus,
            'status_label' => $this->getSpecialBookingRequestStatusLabel($effectiveStatus),
            'viewed_at' => $request['viewed_at'] ?? null,
            'replied_at' => $request['replied_at'] ?? null,
            'created_at' => $request['created_at'] ?? null,
            'created_at_display' => $formattedCreatedAt,
            'reply_subject' => (string) ($request['reply_subject'] ?? ''),
            'reply_message' => (string) ($request['reply_message'] ?? ''),
            'replied_to_email' => (string) ($request['replied_to_email'] ?? ''),
        ];
    }

    private function shouldShowSpecialBookingRequestInPanel(array $request): bool
    {
        return in_array((string) ($request['status'] ?? 'new'), ['new', 'viewed'], true);
    }

    private function sendBookingEmails(array $booking): void
    {
        $uploadModel = new UploadModel();
        $config = $uploadModel->first();
        $notificationEmail = trim((string) ($config['notification_email'] ?? ''));
        $notificationEmailList = array_values(array_filter(array_map('trim', explode(';', $notificationEmail))));

        if ($notificationEmailList !== []) {
            $formattedDate = $this->formatBookingDate((string) ($booking['date'] ?? ''));
            $subjectName = trim((string) ($booking['name'] ?? ''));
            $subjectTimeFrom = trim((string) ($booking['time_from'] ?? ''));
            $subject = "Reserva - Laberinto: {$subjectName} - {$formattedDate} {$subjectTimeFrom}";

            $bookingUrl = site_url('MisReservas/' . rawurlencode($this->buildReservationAccessToken([
                'code' => (string) ($booking['code'] ?? ''),
            ])));
            $html = $this->renderEmailCard([
                'eyebrow' => 'Nueva reserva',
                'title' => $subjectName !== '' ? $subjectName . ' reservo una visita' : 'Se recibio una nueva reserva',
                'intro' => 'La reserva fue creada desde el panel administrativo.',
                'details' => [
                    'Nombre' => (string) ($booking['name'] ?? ''),
                    'Telefono' => (string) ($booking['phone'] ?? ''),
                    'Fecha' => $formattedDate,
                    'Horario' => trim(((string) ($booking['time_from'] ?? '')) . ' a ' . ((string) ($booking['time_until'] ?? ''))),
                    'Visitantes' => (string) ($booking['visitors'] ?? ''),
                    'Total' => '$' . (string) ($booking['total'] ?? ''),
                    'Codigo' => (string) ($booking['code'] ?? ''),
                ],
                'messageHtml' => '<p>Se registro una nueva reserva desde el panel administrativo.</p>',
                'primaryActionUrl' => $bookingUrl,
                'primaryActionLabel' => 'Ver reserva',
            ]);

            $this->sendEmailWithFallback($notificationEmailList, $subject, $html, true);
        }

        $customerEmail = $this->resolveCustomerEmail($booking);
        if ($customerEmail === '') {
            return;
        }

        $customerName = trim((string) ($booking['name'] ?? 'Cliente'));
        $formattedDate = $this->formatBookingDate((string) ($booking['date'] ?? ''));
        $subject = "Reserva confirmada - Laberinto: {$customerName}";

        $bookingLink = site_url('MisReservas/' . rawurlencode($this->buildReservationAccessToken([
            'code' => (string) ($booking['code'] ?? ''),
            'phone' => (string) ($booking['phone'] ?? ''),
            'email' => $customerEmail,
        ])));
        $downloadPdfUrl = !empty($booking['id']) ? site_url('bookingPdf/' . $booking['id']) : '';
        $html = $this->renderEmailCard([
            'eyebrow' => 'Reserva confirmada',
            'title' => 'Tu visita ya quedo confirmada',
            'intro' => 'La reserva fue creada correctamente y ya tenes acceso al detalle completo.',
            'details' => [
                'Nombre' => $customerName,
                'Fecha' => $formattedDate,
                'Horario' => trim(($booking['time_from'] ?? '') . ' a ' . ($booking['time_until'] ?? '')),
                'Cantidad' => (string) ($booking['visitors'] ?? ''),
                'Total' => '$' . (string) ($booking['total'] ?? ''),
                'Pagado' => '$' . (string) ($booking['payment'] ?? '0'),
                'Saldo pendiente' => '$' . (string) ($booking['diference'] ?? '0'),
                'Codigo' => (string) ($booking['code'] ?? ''),
            ],
            'messageHtml' => '<p>Te dejamos accesos rapidos para revisar tu reserva y descargar el comprobante.</p>',
            'primaryActionUrl' => $bookingLink,
            'primaryActionLabel' => 'Ver reserva',
            'secondaryActionUrl' => $downloadPdfUrl,
            'secondaryActionLabel' => $downloadPdfUrl !== '' ? 'Descargar comprobante' : '',
            'supportText' => 'Se asume el compromiso y la responsabilidad de asistir en el dia y horario acordados. En caso de inasistencia, no se realizaran devoluciones y la reprogramacion queda sujeta a disponibilidad.',
        ]);

        $this->sendEmailWithFallback($customerEmail, $subject, $html, true);
    }

    public function index()
    {
        $bookingsModel = new BookingsModel();
        $fieldsModel = new FieldsModel();
        $rateModel = new RateModel();
        $customersModel = new CustomersModel();
        $timeModel = new TimeModel();
        $usersModel = new UsersModel();
        $offerModel = new OffersModel();
        $uploadModel = new UploadModel();
        $valuesModel = new ValuesModel();

        $users = $usersModel->findAll();

        $values = $valuesModel->where('disabled', 0)->findAll();

        $bookings = [];

        foreach ($bookingsModel->getBookings() as $booking) {
            $reserva = [
                'id' => $booking['id'],
                'cancha' => $fieldsModel->getField($booking['id_field'])['name'],
                'fecha' => date("d/m/Y", strtotime($booking['date'])),
                'horario' => $booking['time_from'] . ' a ' . $booking['time_until'],
                'nombre' => $booking['name'],
                'telefono' => $booking['phone'],
                'pago_total' => $booking['total_payment'] == 1 ? 'Si' : 'No',
                'total_reserva' => $booking['total'],
                'diferencia' => $booking['diference'],
                'monto_reserva' => $booking['payment'],
                'metodo_pago' => $booking['payment_method']
            ];

            array_push($bookings, $reserva);
        }

        $getTime = $timeModel->findAll();
        if ($getTime) {
            $time = $getTime[0];
        } else {
            $time = [
                'from' => 0,
                'until' => 0,
                'from_cut' => 0,
                'until_cut' => 0,
                'nocturnal_time' => 0
            ];
        }

        $openingTime = $timeModel->getOpeningTime();

        $getRate = $rateModel->findAll();
        if ($getRate) {
            $rate = $getRate[0];
        } else {
            $rate = 0;
        }

        $getOfferRate = $offerModel->findAll();
        if ($getOfferRate) {
            $offerRate = $getOfferRate[0];
        } else {
            $offerRate = 0;
        }

        $fields = $fieldsModel->findAll();

        $customers = $customersModel->where('deleted', 0)->findAll();

        $logo = $uploadModel->first();

        $latestBookingRow = $bookingsModel->selectMax('date', 'latest_date')->first();
        $latestBookingDate = $latestBookingRow['latest_date'] ?? date('Y-m-d');
        $today = date('Y-m-d');

        if (empty($latestBookingDate) || $latestBookingDate < $today) {
            $latestBookingDate = $today;
        }

        $weekStart = date('Y-m-d', strtotime('monday this week'));

        return view('superadmin/index', [
            'bookings' => $bookings,
            'rate' => $rate,
            'customers' => $customers,
            'time' => $time,
            'openingTime' => $openingTime,
            'fields' => $fields,
            'users' => $users,
            'offerRate' => $offerRate,
            'logo' => $logo,
            'values' => $values,
            'latestBookingDate' => $latestBookingDate,
            'weekStart' => $weekStart,
        ]);
    }

    public function getValue($type)
    {
        $valuesModel = new ValuesModel();
        $value = $valuesModel->where('value', $type)->first();

        try {
            return  $this->response->setJSON($this->setResponse(null, null, $value, 'Respuesta exitosa'));
        } catch (\Exception $e) {
            return  $this->response->setJSON($this->setResponse(404, true, null, $e->getMessage()));
        }
    }

    public function saveValue()
    {
        $valuesModel = new ValuesModel();
        $isAjax = $this->request->isAJAX();

        $nombre = $this->request->getVar('serviceName');
        $valor = $this->request->getVar('serviceAmount');
        $dto = $this->request->getVar('serviceDiscountPercentage');
        $value = $this->request->getVar('serviceValue');
        $id = $this->request->getVar('idValue');

        $query = [
            'name' => $nombre,
            'amount' => $valor,
            'discount_percentage' => $dto === '' ? 0 : $dto,
            'value' => $value,
            'disabled' => 0,
        ];

        if ($nombre == '' || $valor == '') {
            if ($isAjax) {
                return $this->response->setStatusCode(ResponseInterface::HTTP_BAD_REQUEST)
                    ->setJSON(['error' => true, 'message' => 'Debe ingresar todos los datos']);
            }
            return redirect()->to('abmAdmin')->with('msg', ['type' => 'danger', 'body' => 'Debe ingresar todos los datos']);
        }

        if ($value == '') {
            $valor = strtolower(str_replace(' ', '_', $nombre));
            $query['value'] = $valor;
        }

        try {
            if ($id != '') {
                $valuesModel->update($id, $query);
                $savedValue = $valuesModel->find($id);
                if ($isAjax) {
                    return $this->response->setJSON([
                        'error' => false,
                        'action' => 'updated',
                        'message' => 'Actualizado correctamente',
                        'item' => $savedValue,
                    ]);
                }
                return redirect()->to('abmAdmin')->with('msg', ['type' => 'success', 'body' => 'Actualizado correctamente']);
            } else {
                $newId = $valuesModel->insert($query);
                $savedValue = $valuesModel->find($newId);
                if ($isAjax) {
                    return $this->response->setJSON([
                        'error' => false,
                        'action' => 'created',
                        'message' => 'Creado correctamente',
                        'item' => $savedValue,
                    ]);
                }
                return redirect()->to('abmAdmin')->with('msg', ['type' => 'success', 'body' => 'Creado correctamente']);
            }
        } catch (\Exception $e) {
            if ($isAjax) {
                return $this->response->setStatusCode(ResponseInterface::HTTP_BAD_REQUEST)
                    ->setJSON(['error' => true, 'message' => 'Error al insertar datos: ' . $e->getMessage()]);
            }
            return redirect()->to('abmAdmin')->with('msg', ['type' => 'danger', 'body' => 'Error al insertar datos: ' . $e->getMessage()]);
        }
    }

    public function saveField()
    {
        $fieldsModel = new FieldsModel();
        $isAjax = $this->request->isAJAX();

        $this->request->getVar('iluminacion') ? $iluminacion = true : $iluminacion = false;
        $this->request->getVar('tipoTecho') ? $techada = true : $techada = false;

        $nombre = $this->request->getVar('nombre');
        $medidas = $this->request->getVar('medidas');
        $tipoPiso = $this->request->getVar('tipoPiso');
        $tipoCancha = $this->request->getVar('tipoCancha');
        $valor = $this->request->getVar('valor');
        $valorIluminacion = $this->request->getVar('valorIluminacion');


        $query = [
            'name' => $nombre,
            'sizes' => $medidas,
            'floor_type' => $tipoPiso,
            'field_type' => $tipoCancha,
            'ilumination' => $iluminacion,
            'roofed' => $techada,
            'value' => $valor,
            'ilumination_value' => $valorIluminacion,
            'disabled' => 0,
        ];

        if ($nombre == '' || $medidas == '' || $tipoPiso == '' || $tipoCancha == '' || $valor == '' || $valorIluminacion == '') {
            if ($isAjax) {
                return $this->response->setStatusCode(ResponseInterface::HTTP_BAD_REQUEST)
                    ->setJSON(['error' => true, 'message' => 'Debe ingresar todos los datos']);
            }
            return redirect()->to('abmAdmin')->with('msg', ['type' => 'danger', 'body' => 'Debe ingresar todos los datos']);
        }


        try {
            $newId = $fieldsModel->insert($query);
            if ($isAjax) {
                return $this->response->setJSON([
                    'error' => false,
                    'action' => 'created',
                    'item' => $fieldsModel->find($newId),
                    'message' => 'Cancha creada correctamente',
                ]);
            }
        } catch (\Exception $e) {
            if ($isAjax) {
                return $this->response->setStatusCode(ResponseInterface::HTTP_BAD_REQUEST)
                    ->setJSON(['error' => true, 'message' => 'Error al insertar datos: ' . $e->getMessage()]);
            }
            return redirect()->to('abmAdmin')->with('msg', ['type' => 'danger', 'body' => 'Error al insertar datos: ' . $e->getMessage()]);
        }

        return redirect()->to('abmAdmin')->with('msg', ['type' => 'success', 'body' => 'Cancha creada correctamente']);
    }

