    public function resendBookingEmail($id)
    {
        $bookingsModel = new BookingsModel();
        $mercadoPagoModel = new MercadoPagoModel();

        $booking = $bookingsModel->find($id);
        if (!$booking) {
            return $this->response->setStatusCode(ResponseInterface::HTTP_NOT_FOUND)
                ->setJSON(['error' => true, 'message' => 'No se encontro la reserva']);
        }

        $mpPayment = $mercadoPagoModel->where('id_booking', $id)->orderBy('id', 'DESC')->first();
        if ($mpPayment) {
            $booking['payment_id'] = $mpPayment['payment_id'] ?? null;
            $booking['payment_status'] = $mpPayment['status'] ?? null;
        }

        try {
            $this->sendBookingEmails($booking);

            return $this->response->setJSON([
                'error' => false,
                'message' => 'Se intento reenviar el email de la reserva',
            ]);
        } catch (\Throwable $e) {
            return $this->response->setStatusCode(ResponseInterface::HTTP_BAD_REQUEST)
                ->setJSON(['error' => true, 'message' => 'No se pudo reenviar el email']);
        }
    }

    public function getSpecialBookingRequests()
    {
        $specialBookingRequestsModel = new SpecialBookingRequestsModel();

        try {
            $items = $specialBookingRequestsModel
                ->orderBy('created_at', 'DESC')
                ->findAll(30);

            usort($items, static function (array $a, array $b): int {
                $priority = [
                    'new' => 0,
                    'viewed' => 1,
                    'replied' => 2,
                    'confirmed' => 3,
                    'cancelled' => 4,
                ];

                $aPriority = $priority[$a['status'] ?? 'cancelled'] ?? 4;
                $bPriority = $priority[$b['status'] ?? 'cancelled'] ?? 4;

                if ($aPriority !== $bPriority) {
                    return $aPriority <=> $bPriority;
                }

                return strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? ''));
            });

            $transformedItems = array_values(array_filter(
                array_map(fn(array $item) => $this->transformSpecialBookingRequest($item), $items),
                fn(array $item): bool => $this->shouldShowSpecialBookingRequestInPanel($item)
            ));
            usort($transformedItems, static function (array $a, array $b): int {
                $priority = [
                    'new' => 0,
                    'viewed' => 1,
                ];

                $aPriority = $priority[$a['status'] ?? 'viewed'] ?? 1;
                $bPriority = $priority[$b['status'] ?? 'viewed'] ?? 1;

                if ($aPriority !== $bPriority) {
                    return $aPriority <=> $bPriority;
                }

                return strcmp((string) ($b['created_at'] ?? ''), (string) ($a['created_at'] ?? ''));
            });
            $unreadCount = count(array_filter($transformedItems, static fn(array $item): bool => ($item['status'] ?? '') === 'new'));

            return $this->response->setJSON([
                'error' => false,
                'data' => $transformedItems,
                'meta' => [
                    'unreadCount' => $unreadCount,
                ],
            ]);
        } catch (\Throwable $e) {
            return $this->response->setStatusCode(ResponseInterface::HTTP_BAD_REQUEST)
                ->setJSON(['error' => true, 'message' => 'No se pudieron cargar las solicitudes especiales']);
        }
    }

    public function viewSpecialBookingRequest($id)
    {
        $specialBookingRequestsModel = new SpecialBookingRequestsModel();
        $requestItem = $specialBookingRequestsModel->find($id);

        if (!$requestItem) {
            return $this->response->setStatusCode(ResponseInterface::HTTP_NOT_FOUND)
                ->setJSON(['error' => true, 'message' => 'No se encontro la solicitud']);
        }

        if (($requestItem['status'] ?? 'new') === 'new') {
            $specialBookingRequestsModel->update($id, [
                'status' => 'viewed',
                'viewed_at' => date('Y-m-d H:i:s'),
                'updated_at' => date('Y-m-d H:i:s'),
            ]);
            $requestItem = $specialBookingRequestsModel->find($id);
        }

        return $this->response->setJSON([
            'error' => false,
            'data' => $this->transformSpecialBookingRequest($requestItem),
        ]);
    }

    public function replySpecialBookingRequest($id)
    {
        $specialBookingRequestsModel = new SpecialBookingRequestsModel();
        $requestItem = $specialBookingRequestsModel->find($id);

        if (!$requestItem) {
            return $this->response->setStatusCode(ResponseInterface::HTTP_NOT_FOUND)
                ->setJSON(['error' => true, 'message' => 'No se encontro la solicitud']);
        }


        $effectiveStatus = $this->getSpecialBookingRequestEffectiveStatus($requestItem);
        if (in_array($effectiveStatus, ['cancelled', 'confirmed'], true)) {
            return $this->response->setStatusCode(ResponseInterface::HTTP_BAD_REQUEST)
                ->setJSON(['error' => true, 'message' => 'La solicitud ya no admite respuesta por email']);
        }

        $email = trim((string) $this->request->getVar('email'));
        $subject = trim((string) $this->request->getVar('subject'));
        $message = trim((string) $this->request->getVar('message'));

        if ($email === '' || !filter_var($email, FILTER_VALIDATE_EMAIL)) {
            return $this->response->setStatusCode(ResponseInterface::HTTP_BAD_REQUEST)
                ->setJSON(['error' => true, 'message' => 'Debe indicar un email valido']);
        }

        if ($subject === '' || $message === '') {
            return $this->response->setStatusCode(ResponseInterface::HTTP_BAD_REQUEST)
                ->setJSON(['error' => true, 'message' => 'Debe completar asunto y mensaje']);
        }

        $customerName = trim((string) ($requestItem['customer_name'] ?? ''));
        $customerLastName = trim((string) ($requestItem['customer_last_name'] ?? ''));
        $customerFullName = trim($customerName . ' ' . $customerLastName);
        $requestedDate = (string) ($requestItem['requested_date'] ?? '');
        $timeFrom = trim((string) ($requestItem['time_from'] ?? ''));
        $timeUntil = trim((string) ($requestItem['time_until'] ?? ''));
        $confirmationToken = $this->buildReservationAccessToken([
            'type' => 'special_booking_request',
            'request_id' => (int) $id,
            'date' => $requestedDate,
            'field_id' => !empty($requestItem['field_id']) ? (int) $requestItem['field_id'] : null,
            'field_name' => (string) ($requestItem['field_name'] ?? ''),
            'time_from' => $timeFrom,
            'time_until' => $timeUntil,
            'visitors' => (int) ($requestItem['visitors'] ?? 0),
            'minimum_visitors' => (int) ($requestItem['minimum_visitors'] ?? 0),
            'name' => $customerFullName !== '' ? $customerFullName : $customerName,
            'phone' => (string) ($requestItem['customer_phone'] ?? ''),
            'email' => $email,
            'dni' => (string) ($requestItem['customer_dni'] ?? ''),
            'city' => (string) ($requestItem['customer_city'] ?? ''),
            'type_institution' => (string) ($requestItem['customer_type_institution'] ?? ''),
        ]);
        $confirmationUrl = site_url('confirmarReserva/' . rawurlencode($confirmationToken));
        $cancelUrl = site_url('cancelarReserva/' . rawurlencode($confirmationToken));

        $html = $this->renderEmailCard([
            'eyebrow' => 'Respuesta a tu consulta',
            'title' => 'Reserva de fecha cercana',
            'intro' => 'Respondimos tu solicitud especial para una fecha con menos de 48 hs de anticipacion. Si estas de acuerdo, confirma la reserva desde el siguiente enlace y completa el pago para que quede registrada.',
            'details' => [
                'Fecha solicitada' => $this->formatBookingDate((string) ($requestItem['requested_date'] ?? '')),
                'Servicio' => (string) ($requestItem['field_name'] ?? 'No informado'),
                'Horario solicitado' => trim($timeFrom . (($timeFrom !== '' || $timeUntil !== '') ? ' a ' : '') . $timeUntil) ?: 'No informado',
                'Nombre' => (string) ($requestItem['customer_name'] ?? ''),
                'Telefono' => (string) ($requestItem['customer_phone'] ?? ''),
                'Visitantes' => (string) ($requestItem['visitors'] ?? 0),
            ],
            'messageHtml' => nl2br(esc($message)),
            'primaryActionUrl' => $confirmationUrl,
            'primaryActionLabel' => 'Confirmar reserva y pagar',
            'secondaryActionUrl' => $cancelUrl,
            'secondaryActionLabel' => 'Cancelar solicitud',
            'supportText' => 'Podes confirmar la reserva desde el enlace o cancelar esta solicitud si finalmente no la necesitas.',
        ]);

        if (!$this->sendEmailWithFallback($email, $subject, $html, true)) {
            return $this->response->setStatusCode(ResponseInterface::HTTP_BAD_REQUEST)
                ->setJSON(['error' => true, 'message' => 'No se pudo enviar la respuesta']);
        }

        $specialBookingRequestsModel->update($id, [
            'status' => 'replied',
            'viewed_at' => $requestItem['viewed_at'] ?: date('Y-m-d H:i:s'),
            'replied_at' => date('Y-m-d H:i:s'),
            'replied_to_email' => $email,
            'reply_subject' => $subject,
            'reply_message' => $message,
            'updated_at' => date('Y-m-d H:i:s'),
        ]);

        return $this->response->setJSON([
            'error' => false,
            'message' => 'Respuesta enviada correctamente',
            'data' => $this->transformSpecialBookingRequest($specialBookingRequestsModel->find($id)),
        ]);
    }


    public function cancelSpecialBookingRequest($id)
    {
        $specialBookingRequestsModel = new SpecialBookingRequestsModel();
        $requestItem = $specialBookingRequestsModel->find($id);

        if (!$requestItem) {
            return $this->response->setStatusCode(ResponseInterface::HTTP_NOT_FOUND)
                ->setJSON(['error' => true, 'message' => 'No se encontro la solicitud']);
        }

        $effectiveStatus = $this->getSpecialBookingRequestEffectiveStatus($requestItem);
        if ($effectiveStatus === 'confirmed') {
            return $this->response->setStatusCode(ResponseInterface::HTTP_BAD_REQUEST)
                ->setJSON(['error' => true, 'message' => 'La solicitud ya fue confirmada y no puede cancelarse']);
        }

        if ($effectiveStatus === 'cancelled') {
            return $this->response->setJSON([
                'error' => false,
                'message' => 'La solicitud ya estaba cancelada',
                'data' => $this->transformSpecialBookingRequest($requestItem),
            ]);
        }

        $specialBookingRequestsModel->update($id, [
            'status' => 'cancelled',
            'updated_at' => date('Y-m-d H:i:s'),
        ]);

        return $this->response->setJSON([
            'error' => false,
            'message' => 'Solicitud cancelada correctamente',
            'data' => $this->transformSpecialBookingRequest($specialBookingRequestsModel->find($id)),
        ]);
    }

    public function deleteSpecialBookingRequest($id)
    {
        $specialBookingRequestsModel = new SpecialBookingRequestsModel();
        $requestItem = $specialBookingRequestsModel->find($id);

        if (!$requestItem) {
            return $this->response->setStatusCode(ResponseInterface::HTTP_NOT_FOUND)
                ->setJSON(['error' => true, 'message' => 'No se encontro la solicitud']);
        }

        $specialBookingRequestsModel->delete($id);

        return $this->response->setJSON([
            'error' => false,
            'message' => 'Solicitud eliminada correctamente',
        ]);
    }
